public class ModVillagerProfessions {
    public static final VillagerProfession CUSTOM_PROFESSION = register("custom_profession", ModPointsOfInterest.CUSTOM_POI, ImmutableSet.of(), ImmutableSet.of(), SoundEvents.ENTITY_VILLAGER_WORK_ARMORER);
    private static VillagerProfession register(String id, PointOfInterestType poi, ImmutableSet<Item> gatherableItems, ImmutableSet<Block> secondaryJobSites, SoundEvent workSound) {
        return Registry.register(Registries.VILLAGER_PROFESSION, new Identifier("modid", id), new VillagerProfession(id, entry -> entry.value() == poi, entry -> entry.value() == poi, gatherableItems, secondaryJobSites, workSound));
    }
}

public class CustomWorkstationBlock extends Block {
    public CustomWorkstationBlock(Settings settings) { super(settings); }
}

public class ModPointsOfInterest {
    public static final PointOfInterestType CUSTOM_POI = register("custom_poi", RegistryKey.of(RegistryKeys.POINT_OF_INTEREST_TYPE, new Identifier("modid", "custom_poi")), 1, 1, ModBlocks.CUSTOM_WORKSTATION);
    private static PointOfInterestType register(String id, RegistryKey<PointOfInterestType> key, int ticketCount, int searchDistance, Block... blocks) {
        return Registry.register(Registries.POINT_OF_INTEREST_TYPE, key, new PointOfInterestType(Set.of(blocks), ticketCount, searchDistance));
    }
}

